232→// ---------------------------------------------------------------------------
233→// HeaderOpenButton — split button: quick open (last-used) + dropdown
234→// ---------------------------------------------------------------------------
235→
236→function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
237→  const [apps, setApps] = useState<InstalledApp[]>([]);
238→  const [loading, setLoading] = useState(true);
239→  const [open, setOpen] = useState(false);
240→  const [copied, setCopied] = useState(false);
241→  const [lastAppId, setLastAppId] = useLastOpenInApp();
242→  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
243→  const isHoveringRef = useRef(false);
244→
245→  useEffect(() => {
246→    native.apps
247→      .getInstalled()
248→      .then(setApps)
249→      .catch(() => {})
250→      .finally(() => setLoading(false));
251→  }, []);
252→
253→  // Default app: last-used, or first editor in the list
254→  const lastApp = lastAppId ? (apps.find((a) => a.id === lastAppId) ?? null) : null;
255→  const defaultApp = lastApp ?? apps[0] ?? null;
256→
257→  function handleOpenInApp(appId: string) {
258→    setOpen(false);
259→    setLastAppId(appId);
260→    track("open_in_app", { app_id: appId });
261→    native.apps.openIn(appId, workspacePath).catch(() => {});
262→  }
263→
264→  function handleQuickOpen() {
265→    if (loading) return;
266→    if (defaultApp) {
267→      handleOpenInApp(defaultApp.id);
268→    } else {
269→      setOpen(true);
270→    }
271→  }
272→
273→  function handleCopyPath() {
274→    navigator.clipboard
275→      .writeText(workspacePath)
276→      .then(() => {
277→        setCopied(true);
278→        setTimeout(() => setCopied(false), 2000);
279→      })
280→      .catch(() => {});
281→    setOpen(false);
282→  }
283→
284→  function handleOpen() {
285→    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
286→    isHoveringRef.current = true;
287→    setOpen(true);
288→  }
289→
290→  function handleClose() {
291→    isHoveringRef.current = false;
292→    closeTimeoutRef.current = setTimeout(() => {
293→      if (!isHoveringRef.current) setOpen(false);
294→    }, 50);
295→  }
296→
297→  useEffect(() => {
298→    return () => {
299→      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
300→    };
301→  }, []);
