 53→/**
 54→ * SidebarResizeHandle — drag handle on the sidebar's right edge.
 55→ * Must be rendered inside SidebarProvider to access sidebar open state.
 56→ * Reports isDragging so the parent can disable sidebar CSS transitions during resize.
 57→ */
 58→function SidebarResizeHandle({
 59→  onSizeChange,
 60→  onDraggingChange,
 61→}: {
 62→  onSizeChange: (size: number | null) => void;
 63→  onDraggingChange: (dragging: boolean) => void;
 64→}) {
 65→  const { open } = useSidebar();
 66→
 67→  const { handleProps, isDragging } = useResizeHandle({
 68→    onSizeChange,
 69→    enabled: open,
 70→    direction: "horizontal",
 71→    mode: "primary",
 72→    minPrimarySize: 200,
 73→    minSecondarySize: 400,
 74→  });
 75→
 76→  // Notify parent of drag state changes to disable sidebar transitions
 77→  useEffect(() => {
 78→    onDraggingChange(isDragging);
 79→  }, [isDragging, onDraggingChange]);
 80→
 81→  if (!open) return null;
 82→
 83→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
 84→}
 85→
 86→export function MainLayout() {
 87→  // Zustand stores - Global state (ID-only; full object derived from React Query below)
 88→  const selectedWorkspaceId = useWorkspaceStore((state) => state.selectedWorkspaceId);
 89→  const selectWorkspace = useWorkspaceStore((state) => state.selectWorkspace);
 90→
 91→  const showNewWorkspaceModal = useUIStore((s) => s.showNewWorkspaceModal);
 92→  const newWorkspaceMode = useUIStore((s) => s.newWorkspaceMode);
 93→  const showSystemPromptModal = useUIStore((s) => s.showSystemPromptModal);
 94→  const settingsOpen = useUIStore((s) => s.settingsOpen);
 95→  const openNewWorkspaceModal = useUIStore((s) => s.openNewWorkspaceModal);
 96→  const closeNewWorkspaceModal = useUIStore((s) => s.closeNewWorkspaceModal);
 97→  const closeSystemPromptModal = useUIStore((s) => s.closeSystemPromptModal);
 98→
 99→  // TanStack Query
100→  const workspacesQuery = useWorkspacesByRepo();
101→
102→  const repoGroups = useMemo(() => workspacesQuery.data ?? [], [workspacesQuery.data]);
103→  const loading = workspacesQuery.isLoading;
104→
105→  // Derive the full workspace object from React Query data.
106→  // The store only holds an ID; this useMemo resolves it to a Workspace
107→  // on every React Query refresh, eliminating the old sync effect entirely.
108→  const selectedWorkspace = useMemo(() => {
109→    if (!selectedWorkspaceId || !repoGroups.length) return null;
110→    for (const group of repoGroups) {
111→      const found = group.workspaces.find((w) => w.id === selectedWorkspaceId);
112→      if (found) return found;
113→    }
114→    return null;
115→  }, [selectedWorkspaceId, repoGroups]);
116→
117→  const selectedWorkspaceIdRef = useRef(selectedWorkspaceId);
118→  useEffect(() => {
119→    selectedWorkspaceIdRef.current = selectedWorkspaceId;
120→  });
121→
122→  // Bulk-fetch diff stats for all workspaces (replaces per-item useDiffStats in sidebar)
123→  const bulkDiffStatsQuery = useBulkDiffStats(repoGroups);
124→
125→  // Sidebar resize: null = default 344px, number = user-set width
126→  const [sidebarWidth, setSidebarWidth] = useState<number | null>(null);
127→  // Tracks drag state to disable sidebar CSS transitions during resize
128→  const [sidebarDragging, setSidebarDragging] = useState(false);
129→
130→  // GitHub picker modal state
131→  const [githubPickerRepoId, setGithubPickerRepoId] = useState<string | null>(null);
132→
133→  // Ref for inserting text from browser element selector
134→  const workspaceChatPanelRef = useRef<SessionPanelRef | null>(null);
135→
136→  // Queries for repos, settings
137→  const reposQuery = useRepos();
138→  const settingsQuery = useSettingsQuery();
139→
140→  const repos = reposQuery.data || [];
141→  const username = settingsQuery.data?.user_name || "My Account";
142→
143→  // GitHub CLI status — gates PR polling
144→  const ghStatusQuery = useGhStatus();
145→
146→  // PR status query — gated on gh CLI, polls while agent is working
147→  const prStatusQuery = usePRStatus(selectedWorkspace?.id || null, {
148→    ghInstalled: ghStatusQuery.data?.isInstalled,
149→    ghAuthenticated: ghStatusQuery.data?.isAuthenticated,
150→    sessionStatus: selectedWorkspace?.session_status ?? undefined,
151→  });
152→
153→  // --- Extracted hooks ---
154→
155→  const repoActions = useRepoActions({
156→    selectWorkspace,
157→    openNewWorkspaceModal,
158→    closeNewWorkspaceModal,
159→  });
160→
161→  // Derive repo name for GitHub picker modal from repoGroups
162→  const githubPickerRepoName = useMemo(() => {
163→    if (!githubPickerRepoId) return "";
164→    const group = repoGroups.find((g) => g.repo_id === githubPickerRepoId);
165→    return group?.repo_name ?? "";
166→  }, [githubPickerRepoId, repoGroups]);
167→
168→  // Hide native WebContentsViews when any dialog is open — they render above
169→  // the DOM so dialogs would appear behind them. BrowserTab's own visible
170→  // effect handles re-showing when the dialog closes.
171→  const commandPaletteOpen = useUIStore((s) => s.commandPaletteOpen);
172→  const anyDialogOpen =
173→    showNewWorkspaceModal ||
174→    showSystemPromptModal ||
175→    commandPaletteOpen ||
176→    !!githubPickerRepoId ||
177→    repoActions.showCloneModal;
178→  useEffect(() => {
179→    if (anyDialogOpen) {
180→      native.browserViews.hideAll().catch(() => {});
181→    }
182→  }, [anyDialogOpen]);
183→
184→  // --- System prompt (inline — small scope, one modal) ---
185→
186→  const systemPromptQuery = useSystemPrompt(selectedWorkspace?.id || null);
187→  const updateSystemPromptMutation = useUpdateSystemPrompt();
188→  // Track user edits separately; reset to null when modal closes so the
