import { useState, useCallback } from "react";

const STORAGE_KEY = "deus:lastRunTask";

/** Read last-run task name directly from localStorage (non-reactive). */
export function getLastRunTaskName(): string | null {
  try {
    return localStorage.getItem(STORAGE_KEY);
  } catch {
    return null;
  }
}

/** Write last-run task name to localStorage. */
export function setLastRunTaskName(taskName: string): void {
  try {
    localStorage.setItem(STORAGE_KEY, taskName);
  } catch {
    // localStorage unavailable
  }
}

/** Reactive hook for the last-run task name. */
export function useLastRunTask(): [string | null, (taskName: string) => void] {
  const [lastTask, setLastTaskState] = useState<string | null>(() => getLastRunTaskName());

  const setLastTask = useCallback((taskName: string) => {
    setLastRunTaskName(taskName);
    setLastTaskState(taskName);
  }, []);

  return [lastTask, setLastTask];
}

