          className="text-text-muted cursor-pointer gap-2 py-1.5 text-xs"
        >
          <Settings className="h-3.5 w-3.5 shrink-0" />
          Environment settings
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

