            >
              <DefaultIcon className="h-3.5 w-3.5 shrink-0" />
              <span className="max-w-[100px] shrink-0 truncate text-sm font-medium">
                {defaultTask.name}
              </span>
            </button>
          </TooltipTrigger>
          <TooltipContent side="bottom">
            <p className="text-xs">{tooltipText}</p>
