        onPointerEnter={handleOpen}
        onPointerLeave={handleClose}
      >
        {tasks.map((task) => {
          const Icon = TASK_ICON_MAP[task.icon] ?? Terminal;
          const isDefault = task.name === defaultTask.name;

          return (
            <DropdownMenuItem
